707	    /// Generates a random height and returns it.
708	    fn random_height(&self) -> usize {
709	        // Pseudorandom number generation from "Xorshift RNGs" by George Marsaglia.
710	        //
711	        // This particular set of operations generates 32-bit integers. See:
712	        // https://en.wikipedia.org/wiki/Xorshift#Example_implementation
713	        let mut num = self.hot_data.seed.load(Ordering::Relaxed);
714	        num ^= num << 13;
715	        num ^= num >> 17;
716	        num ^= num << 5;
717	        self.hot_data.seed.store(num, Ordering::Relaxed);
718	
719	        let mut height = cmp::min(MAX_HEIGHT, num.trailing_zeros() as usize + 1);
720	        unsafe {
721	            // Keep decreasing the height while it's much larger than all towers currently in the
722	            // skip list.
723	            //
724	            // Note that we're loading the pointer only to check whether it is null, so it's okay
725	            // to use `epoch::unprotected()` in this situation.
726	            while height >= 4
727	                && self
728	                    .head
729	                    .get_level(height - 2)
730	                    .load(Ordering::Relaxed, epoch::unprotected())
731	                    .is_null()
732	            {
733	                height -= 1;
734	            }
735	        }
736	
737	        // Track the max height to speed up lookups
738	        let mut max_height = self.hot_data.max_height.load(Ordering::Relaxed);
739	        while height > max_height {
740	            match self.hot_data.max_height.compare_exchange_weak(
741	                max_height,
742	                height,
743	                Ordering::Relaxed,
744	                Ordering::Relaxed,
745	            ) {
746	                Ok(_) => break,
747	                Err(h) => max_height = h,
748	            }
749	        }
750	        height
751	    }
