753	    /// If we encounter a deleted node while searching, help with the deletion
754	    /// by attempting to unlink the node from the list.
755	    ///
756	    /// If the unlinking is successful then this function returns the next node
757	    /// with which the search should continue on the current level.
758	    #[cold]
759	    unsafe fn help_unlink<'a>(
760	        &'a self,
761	        pred: &'a Atomic<Node<K, V>>,
762	        curr: NodeRef<'a, K, V>,
763	        succ: Shared<'a, Node<K, V>>,
764	        guard: &'a Guard,
765	    ) -> Option<Shared<'a, Node<K, V>>> {
766	        // If `succ` is marked, that means `curr` is removed. Let's try
767	        // unlinking it from the skip list at this level.
768	        match pred.compare_exchange(
769	            Shared::from(curr.ptr.as_ptr() as *const Node<K, V>),
770	            succ.with_tag(0),
771	            Ordering::Release,
772	            Ordering::Relaxed,
773	            guard,
774	        ) {
775	            Ok(_) => {
776	                unsafe { curr.decrement(guard) }
777	                Some(succ.with_tag(0))
778	            }
779	            Err(_) => None,
780	        }
781	    }
