843	        unsafe {
844	            'search: loop {
845	                // The current level we're at.
846	                let mut level = self.hot_data.max_height.load(Ordering::Relaxed);
847	
848	                // Fast loop to skip empty tower levels.
849	                while level >= 1
850	                    && self
851	                        .head
852	                        .get_level(level - 1)
853	                        .load(Ordering::Relaxed, guard)
854	                        .is_null()
855	                {
856	                    level -= 1;
857	                }
858	
859	                // The current best node
860	                let mut result = None;
861	
862	                // The predecessor node
863	                let mut pred = self.head.as_tower();
864	
865	                while level >= 1 {
866	                    level -= 1;
867	
868	                    // Two adjacent nodes at the current level.
869	                    let mut curr = pred.get_level(level).load_consume(guard);
870	
871	                    // If `curr` is marked, that means `pred` is removed and we have to restart the
872	                    // search.
873	                    if curr.tag() == 1 {
874	                        continue 'search;
875	                    }
876	
877	                    // Iterate through the current level until we reach a node with a key greater
878	                    // than or equal to `key`.
879	                    while let Some(c) = NodeRef::from_shared(curr) {
880	                        let succ = c.get_level(level).load_consume(guard);
881	
882	                        if succ.tag() == 1 {
883	                            if let Some(c) = self.help_unlink(pred.get_level(level), c, succ, guard)
884	                            {
885	                                // On success, continue searching through the current level.
886	                                curr = c;
887	                                continue;
888	                            } else {
889	                                // On failure, we cannot do anything reasonable to continue
890	                                // searching from the current position. Restart the search.
891	                                continue 'search;
892	                            }
893	                        }
894	
895	                        // If `curr` contains a key that is greater than (or equal) to `key`, we're
896	                        // done with this level.
897	                        //
898	                        // The condition determines whether we should stop the search. For the upper
899	                        // bound, we return the last node before the condition became true. For the
900	                        // lower bound, we return the first node after the condition became true.
901	                        if upper_bound {
902	                            if !below_upper_bound(&self.comparator, &bound, &c.key) {
903	                                break;
