905	                            result = Some(c);
906	                        } else if above_lower_bound(&self.comparator, &bound, &c.key) {
907	                            result = Some(c);
908	                            break;
909	                        }
910	
911	                        // Move one step forward.
912	                        pred = c.as_tower();
913	                        curr = succ;
914	                    }
915	                }
916	
917	                return result;
918	            }
