1010	    /// Inserts an entry with the specified `key` and `value`.
1011	    ///
1012	    /// If `replace` is `true`, then any existing entry with this key will first be removed.
1013	    fn insert_internal<F, CompareF>(
1014	        &self,
1015	        key: K,
1016	        value: F,
1017	        replace: CompareF,
1018	        guard: &Guard,
1019	    ) -> RefEntry<'_, K, V, C>
1020	    where
1021	        C: Comparator<K>,
1022	        F: FnOnce() -> V,
1023	        CompareF: Fn(&V) -> bool,
1024	    {
1025	        self.check_guard(guard);
1026	
1027	        unsafe {
1028	            // Rebind the guard to the lifetime of self. This is a bit of a
1029	            // hack but it allows us to return references that are not bound to
1030	            // the lifetime of the guard.
1031	            let guard = &*(guard as *const _);
1032	
1033	            // First try searching for the key.
1034	            // Note that the `Ord` implementation for `K` may panic during the search.
1035	            let mut search = self.search_position(&key, guard);
1036	            if let Some(r) = search.found {
1037	                let replace = replace(&r.value);
1038	                if !replace {
1039	                    // If a node with the key was found and we're not going to replace it, let's
1040	                    // try returning it as an entry.
1041	                    if let Some(e) = RefEntry::try_acquire(self, r) {
1042	                        return e;
1043	                    }
1044	                }
1045	            }
1046	
1047	            // create value before creating node, so extra allocation doesn't happen if value() function panics
1048	            let value = value();
1049	            // Create a new node.
1050	            let height = self.random_height();
1051	            let (node, n) = {
1052	                // The reference count is initially two to account for:
1053	                // 1. The entry that will be returned.
1054	                // 2. The link at the level 0 of the tower.
1055	                let n = Node::<K, V>::alloc(height, 2);
1056	
1057	                // Write the key and the value into the node.
1058	                ptr::addr_of_mut!((*n).key).write(key);
1059	                ptr::addr_of_mut!((*n).value).write(value);
1060	
1061	                (
1062	                    Shared::<Node<K, V>>::from(n as *const _),
1063	                    NodeRef::new(NonNull::new_unchecked(n)),
1064	                )
1065	            };
1066	
1067	            // Optimistically increment `len`.
1068	            self.hot_data.len.fetch_add(1, Ordering::Relaxed);
1069	
1070	            loop {
1071	                // Set the lowest successor of `n` to `search.right[0]`.
1072	                n.get_level(0).store(search.right[0], Ordering::Relaxed);
1073	
1074	                // Try installing the new node into the skip list (at level 0).
1075	                // TODO(Amanieu): can we use release ordering here?
1076	                if search.left[0]
1077	                    .get_level(0)
1078	                    .compare_exchange(
1079	                        search.right[0],
1080	                        node,
1081	                        Ordering::SeqCst,
1082	                        Ordering::SeqCst,
1083	                        guard,
1084	                    )
1085	                    .is_ok()
1086	                {
1087	                    // This node has been abandoned
1088	                    if let Some(r) = search.found {
1089	                        if r.mark_tower() {
