1135	            // Build the rest of the tower above level 0.
1136	            'build: for level in 1..height {
1137	                loop {
1138	                    // Obtain the predecessor and successor at the current level.
1139	                    let pred = search.left[level];
1140	                    let succ = search.right[level];
1141	
1142	                    // Load the current value of the pointer in the tower at this level.
1143	                    // TODO(Amanieu): can we use relaxed ordering here?
1144	                    let next = n.get_level(level).load(Ordering::SeqCst, guard);
