1369	    /// Iterates over the map and removes every entry.
1370	    pub fn clear(&self, guard: &mut Guard) {
1371	        self.check_guard(guard);
1372	
1373	        /// Number of steps after which we repin the current thread and unlink removed nodes.
1374	        const BATCH_SIZE: usize = 100;
1375	
1376	        loop {
1377	            {
1378	                // Search for the first entry in order to unlink all the preceding entries
1379	                // we have removed.
1380	                //
1381	                // By unlinking nodes in batches we make sure that the final search doesn't
1382	                // unlink all nodes at once, which could keep the current thread pinned for a
1383	                // long time.
1384	                let mut entry = self.lower_bound::<K>(Bound::Unbounded, guard);
1385	
1386	                for _ in 0..BATCH_SIZE {
1387	                    // Stop if we have reached the end of the list.
1388	                    let e = match entry {
1389	                        None => return,
1390	                        Some(e) => e,
1391	                    };
1392	
1393	                    // Before removing the current entry, first obtain the following one.
1394	                    let next = e.next();
1395	
1396	                    // Try removing the current entry.
1397	                    if e.node.mark_tower() {
1398	                        // Success! Decrement `len`.
1399	                        self.hot_data.len.fetch_sub(1, Ordering::Relaxed);
1400	                    }
1401	
1402	                    entry = next;
1403	                }
1404	            }
1405	
1406	            // Repin the current thread because we don't want to keep it pinned in the same
1407	            // epoch for a too long time.
1408	            guard.repin();
1409	        }
